INSERT INTO `memory_entry`
(`title`, `summary`, `content`, `memory_date`, `cover_image_url`, `cover_storage_path`, `mood_tags`, `is_featured`, `visibility`, `sort_order`, `favorite_count`)
VALUES
('把水彩举到灯下的晚上','她把桌上的水彩制服插画拿起来给镜头看，像把今晚最认真、也最柔软的一点成果安静递了过来。','那天晚上书桌很满，线稿、水彩、铅笔和一些还没完全整理好的小东西都摊在灯下。\n\n她坐在桌前，把画好的制服插画轻轻举起来，像是在说，你看，这就是我今晚慢慢画出来的东西。不是正式展示，也不是刻意摆拍，只是很自然地把正在发生的那一点点喜悦分享出来。她眼里的神情很平静，可就是这份不急着说明的认真，让那张画比平时更容易被记住。\n\n后来再回头看这张照片，会觉得它记录下来的不只是作品本身，而是她在夜晚里专注生活的样子。那种把时间一点点花在喜欢的事上、再把成果轻轻递出来的温柔，本身就很值得写进手账里。','2026-06-24','/uploads/photos/205_小可_书桌水彩制服插画展示照.png','photos/205_小可_书桌水彩制服插画展示照.png','书桌,插画,夜晚',1,'PUBLIC',340,NULL),
('海边帽檐下的夏天','海风把帽檐吹得很轻，她在水手服和亮光里看过来，像把整个夏天都收进了这一眼里。','海边那天很亮，风也一直没停。\n\n她戴着帽子站在水边，水手服的线条被海风吹得很轻，连发丝都带着一点透明感。她抬眼看过来的时候，并没有很夸张的表情，只是安安静静地站在那里，却让人一下子记住了那天的光。后来那张全身站姿也很好看，像把海边的清爽和她身上的安静放在了同一页里。\n\n我会喜欢这组照片，不只是因为它们有夏天的颜色。更因为她站在海风里的样子，很像平时不太会主动说出口的柔软，被海边的亮光替她说出来了一点。','2026-06-25','/uploads/photos/211_小可_海边水手服帽子近景照.png','photos/211_小可_海边水手服帽子近景照.png','海边,水手服,夏天',1,'PUBLIC',350,NULL),
('和室里像故事一样的片刻','她坐在和室里，巫女服和木质背景把画面压得很安静，像一段不小心被翻开的旧故事。','和室的光线总是比别的地方更慢一点。\n\n她穿着巫女服坐在房间里，木地板、纸门和窗边的留白都把画面衬得很安静。她没有做很明显的动作，只是坐着、站着、让衣摆和光线自己慢慢落下来，就已经很像故事里的一个场景。那种感觉很特别，不像日常照片那样直接，却让人很容易在脑海里替它补上前后的情节。\n\n所以我想把它写进手账。不是因为它多热闹，而是因为它太完整了。完整到像短短几张照片，就足够装下一整个安静又温柔的午后。','2026-06-25','/uploads/photos/213_小可_和室巫女服坐姿照.png','photos/213_小可_和室巫女服坐姿照.png','和室,巫女服,安静',1,'PUBLIC',360,NULL),
('练功房里把呼吸放稳的时候','她扶着把杆站在舞蹈室里，红色练功服把状态衬得很鲜明，像一整晚的力气都慢慢落在了动作里。','舞蹈室的地板总会把脚步声和呼吸声放得很清楚。\n\n她站在把杆边，红色练功服在灯下很亮，可最让人记住的还是她整个人的状态。不是舞台上的那种热烈，而是训练时很稳的认真。动作要到位，身体要跟上，呼吸也要一点点放平，那种安静里的用力，反而比很多热闹时刻都更动人。\n\n后来我再看这组照片，会觉得它很像小可的另一面。平时的柔软还在，但更多了一点倔强和坚持。不是为了被谁看见，只是很认真地把该练的每一步都练完。','2026-06-25','/uploads/photos/214_小可_舞蹈室红色练功服把杆照.png','photos/214_小可_舞蹈室红色练功服把杆照.png','舞蹈室,练功,认真',0,'PUBLIC',370,NULL),
('灯光亮起前先握好话筒','她站在舞台彩屏前握着话筒，像还没开口，整个人就已经被灯光轻轻托住了。','舞台上的灯总是比人群更早亮起来。\n\n她站在彩屏前，手里握着话筒，背景颜色很浓，灯光也很亮，可她本人却还是带着那种熟悉的安静。好像正式开始之前，她先把自己的呼吸收稳，把表情收好，然后再慢慢走进声音和聚光灯里。那种准备开始的片刻，往往比真正开口的一瞬还更让人心动。\n\n我很想把这张留进手账，因为它记录的是一个临界点。舞台还没真正热起来，可她已经站在那里了。那种在热闹开始之前，先悄悄做好准备的认真，特别像她。','2026-06-25','/uploads/photos/216_小可_舞台彩屏前手持话筒照.png','photos/216_小可_舞台彩屏前手持话筒照.png','舞台,话筒,灯光',1,'PUBLIC',380,NULL);
